const now = new Date();
const parts = now.toLocaleString('en-US', {
  timeZone: 'America/Chicago',
  hour12: false
}).split(', ');
const dateParts = parts[0].split('/');
const month = dateParts[0].padStart(2, '0');
const day = dateParts[1].padStart(2, '0');
const year = dateParts[2];
return [{
  json: {
    today_mmdd: `${month}-${day}`,
    today_yyyy: year
  }
}];

const todayMmdd = $('Get Today').first().json.today_mmdd;
const todayYyyy = $('Get Today').first().json.today_yyyy;
const rows = $input.all();

const matches = rows.filter(row => {
  const bday = String(row.json.birthday || '').trim();
  const anniv = String(row.json.transaction_anniversary || '').trim();
  const bdaySentYear = String(row.json.birthday_sent_year || '').trim();
  const annexSentYear = String(row.json.anniversary_sent_year || '').trim();

  const bdayMatch = bday !== '' && bday === todayMmdd && bdaySentYear !== todayYyyy;
  const annexMatch = anniv !== '' && anniv.slice(5, 10) === todayMmdd && annexSentYear !== todayYyyy;

  return bdayMatch || annexMatch;
});

return matches;

const row = $input.first().json;
const agentName = $('Set Agent Config').first().json.agent_name;
const todayMmdd = $('Get Today').first().json.today_mmdd;
const todayYyyy = $('Get Today').first().json.today_yyyy;

const bday = String(row.birthday || '').trim();
const anniv = String(row.transaction_anniversary || '').trim();
const bdaySentYear = String(row.birthday_sent_year || '').trim();
const annexSentYear = String(row.anniversary_sent_year || '').trim();

const isBday = bday !== '' && bday === todayMmdd && bdaySentYear !== todayYyyy;
const isAnniv = anniv !== '' && anniv.slice(5, 10) === todayMmdd && annexSentYear !== todayYyyy;

let eventType;
if (isBday && isAnniv) eventType = 'BIRTHDAY AND ANNIVERSARY';
else if (isBday) eventType = 'BIRTHDAY';
else eventType = 'TRANSACTION ANNIVERSARY';

let yearsElapsed = '';
if (isAnniv) {
  const txYear = parseInt(anniv.slice(0, 4), 10);
  yearsElapsed = parseInt(todayYyyy, 10) - txYear;
}

const prompt = `You are drafting a brief, warm personal message from a real estate agent to a past client.\n\nEvent: ${eventType}\nClient name: [DATA]${row.lead_name}[/DATA]\n${isAnniv ? `Property address: [DATA]${row.property_address || ''}[/DATA]\nYears since transaction: ${yearsElapsed}` : ''}\nAgent name: [DATA]${agentName}[/DATA]\n\nGuidelines:\n- Warm and personal, NOT salesy. No calls to action, no \"let me know if you're thinking of buying/selling.\"\n- 2-3 sentences max.\n- Birthday: simple well-wish, light warmth.\n- Anniversary: acknowledge the milestone, reference the property, wish them well.\n- Sign off with the agent's first name only.\n\nReturn exactly:\nEMAIL_SUBJECT: ...\nEMAIL_BODY: ...\nSMS_TEXT: ... (under 160 characters)`;

return [{
  json: {
    lead_name: row.lead_name,
    email: row.email,
    phone: row.phone,
    property_address: row.property_address || '',
    birthday_sent_year: bdaySentYear,
    anniversary_sent_year: annexSentYear,
    is_bday: isBday,
    is_anniv: isAnniv,
    event_type: eventType,
    years_elapsed: yearsElapsed,
    today_yyyy: todayYyyy,
    prompt
  }
}];

const upstream = $('Build Prompt').first().json;
const raw = $input.first().json.content[0].text;
const cleaned = raw.replace(/```[\w]*\n?/g, '').trim();

const subjectMatch = cleaned.match(/EMAIL_SUBJECT:\s*(.+)/);
const bodyMatch = cleaned.match(/EMAIL_BODY:\s*([\s\S]+?)(?=SMS_TEXT:|$)/);
const smsMatch = cleaned.match(/SMS_TEXT:\s*(.+)/);

return [{
  json: {
    ...upstream,
    email_subject: subjectMatch ? subjectMatch[1].trim() : 'Thinking of you',
    email_body: bodyMatch ? bodyMatch[1].trim() : '',
    sms_text: smsMatch ? smsMatch[1].trim() : ''
  }
}];

const data = $('Parse Response').first().json;
return [{
  json: {
    email: data.email,
    birthday_sent_year: data.is_bday ? data.today_yyyy : (data.birthday_sent_year || ''),
    anniversary_sent_year: data.is_anniv ? data.today_yyyy : (data.anniversary_sent_year || '')
  }
}];
